content.query:
let start=ago(30d);
let visitors=customEvents | where timestamp > start and name == 'landing_page_viewed' | summarize Visitors=dcount(tostring(customDimensions.session_id));
let signups=customEvents | where timestamp > start and name == 'signup_completed' | summarize Signups=count();
let activations=customEvents | where timestamp > start and name == 'activation_completed' | summarize Activations=count();
let purchases=customEvents | where timestamp > start and name in ('checkout_completed','iap_purchase_completed','memory_book_order_completed') | summarize Purchases=count(), Revenue=sum(todouble(customMeasurements.amount_usd));
visitors | extend k=1 | join kind=fullouter (signups | extend k=1) on k | join kind=fullouter (activations | extend k=1) on k | join kind=fullouter (purchases | extend k=1) on k | project Visitors=coalesce(Visitors,0), Signups=coalesce(Signups,0), Activations=coalesce(Activations,0), Purchases=coalesce(Purchases,0), RevenueUsd=coalesce(Revenue,0.0), SignupRate=iff(Visitors == 0, 0.0, round(100.0 * Signups / Visitors, 2)), ActivationRate=iff(Signups == 0, 0.0, round(100.0 * Activations / Signups, 2)), PurchaseRate=iff(Visitors == 0, 0.0, round(100.0 * Purchases / Visitors, 2))

let requestFailures=requests | where timestamp > ago(24h) and success == false | summarize Count=count() | extend Source='API failed requests';
let exceptions=exceptions | where timestamp > ago(24h) | summarize Count=count() | extend Source='Exceptions';
let paymentErrors=customEvents | where timestamp > ago(24h) and name in ('payment_error','gift_code_redemption_failed') | summarize Count=count() | extend Source='Payment/code errors';
requestFailures | union exceptions | union paymentErrors | project Source, Count
